// ─── Content Preview Popover ──────────────────────────────────────────────────
function ContentPreviewPopover({ item }: { item: ContentResponse }) {
  const fileUrl      = (item as any).file_url ?? (item as any).url ?? null
  const thumbnailUrl = (item as any).thumbnail_url ?? null
  const textBody     = (item as any).text_body ?? (item as any).body ?? null

  return (
    <div
      className="absolute left-[calc(100%+12px)] top-1/2 -translate-y-1/2 z-50
                 w-[220px] bg-white rounded-[14px] border-[1.5px] border-[#DDD6FE]
                 overflow-hidden pointer-events-none
                 opacity-0 scale-95 group-hover:opacity-100 group-hover:scale-100
                 transition-all duration-150"
      style={{ boxShadow: "0 8px 28px rgba(45,0,82,0.14)" }}
    >
      {/* ── Thumbnail ── */}
      <div className="w-full relative" style={{ aspectRatio: "16/10" }}>

        {item.content_type === "video" && (
          fileUrl ? (
            <>
              <video
                src={fileUrl}
                className="w-full h-full object-cover"
                poster={thumbnailUrl ?? undefined}
                preload="metadata"
                muted
              />
              <div className="absolute inset-0 bg-black/30 flex items-center justify-center">
                <div className="w-8 h-8 rounded-full bg-white/90 flex items-center justify-center text-[#8A2BE2]">
                  <svg width="14" height="14" viewBox="0 0 16 16" fill="currentColor">
                    <path d="M4 2.5v11l9-5.5-9-5.5Z"/>
                  </svg>
                </div>
              </div>
            </>
          ) : thumbnailUrl ? (
            <>
              <img src={thumbnailUrl} alt={item.title} className="w-full h-full object-cover" />
              <div className="absolute inset-0 bg-black/30 flex items-center justify-center">
                <div className="w-8 h-8 rounded-full bg-white/90 flex items-center justify-center text-[#8A2BE2]">
                  <svg width="14" height="14" viewBox="0 0 16 16" fill="currentColor">
                    <path d="M4 2.5v11l9-5.5-9-5.5Z"/>
                  </svg>
                </div>
              </div>
            </>
          ) : (
            <div className="w-full h-full bg-[#1a0030] flex flex-col items-center justify-center gap-1.5">
              <div className="w-8 h-8 rounded-full bg-white/10 flex items-center justify-center text-white/50">
                <svg width="14" height="14" viewBox="0 0 16 16" fill="currentColor">
                  <path d="M4 2.5v11l9-5.5-9-5.5Z"/>
                </svg>
              </div>
              <span className="text-[9px] text-white/30 font-medium">Video</span>
            </div>
          )
        )}

        {item.content_type === "image" && (
          (fileUrl || thumbnailUrl) ? (
            <img
              src={fileUrl ?? thumbnailUrl}
              alt={item.title}
              className="w-full h-full object-cover"
            />
          ) : (
            <div className="w-full h-full bg-[#F3E8FF] flex flex-col items-center justify-center gap-1.5">
              <svg width="20" height="20" viewBox="0 0 20 20" fill="none" stroke="#C4B5D4" strokeWidth="1.4" strokeLinecap="round">
                <rect x="2" y="2" width="16" height="16" rx="3"/>
                <circle cx="7" cy="7.5" r="1.5"/>
                <path d="M2 14l4-4 3 3 3-4 6 6"/>
              </svg>
              <span className="text-[9px] text-[#C4B5D4] font-medium">Image</span>
            </div>
          )
        )}

        {item.content_type === "pdf" && (
          <div className="w-full h-full bg-[#FBF8FF] flex flex-col items-center justify-center gap-1.5">
            <div className="w-8 h-8 rounded-[9px] bg-[#F3E8FF] border border-[#EDE5F8] flex items-center justify-center text-[#8A2BE2]">
              <svg width="12" height="12" viewBox="0 0 13 13" fill="none" stroke="currentColor" strokeWidth="1.5">
                <path d="M3 1h5l3 3v8a1 1 0 0 1-1 1H3a1 1 0 0 1-1-1V2a1 1 0 0 1 1-1Z"/>
                <path d="M7.5 1v3.5H11M4 7h5M4 9.5h3"/>
              </svg>
            </div>
            <span className="text-[9px] text-[#A08DBE] font-semibold uppercase tracking-wide">
              PDF Document
            </span>
          </div>
        )}

        {item.content_type === "text" && (
          <div className="w-full h-full bg-[#FBF8FF] p-3 flex flex-col justify-start overflow-hidden">
            {textBody ? (
              <p
                className="text-[11px] text-[#6B4F8A] leading-[1.6] line-clamp-4"
                style={{ fontFamily: "Georgia, serif" }}
              >
                {textBody}
              </p>
            ) : (
              <div className="flex flex-col items-center justify-center h-full gap-1.5">
                <svg width="18" height="18" viewBox="0 0 18 18" fill="none" stroke="#C4B5D4" strokeWidth="1.4" strokeLinecap="round">
                  <path d="M3 4h12M3 8h8M3 12h10M3 16h6"/>
                </svg>
                <span className="text-[9px] text-[#C4B5D4] font-medium">Text post</span>
              </div>
            )}
          </div>
        )}
      </div>

      {/* ── Info ── */}
      <div className="px-3 pt-2.5 pb-3">
        <p className="text-[12px] font-semibold text-[#2D0052] leading-snug mb-1.5"
          style={{ display: "-webkit-box", WebkitLineClamp: 2, WebkitBoxOrient: "vertical", overflow: "hidden" }}>
          {item.title}
        </p>
        <div className="flex items-center gap-1.5 flex-wrap">
          <StatusPill published={item.is_published} />
          <span className="text-[10.5px] text-[#A08DBE]">
            {TYPE_CONFIG[item.content_type].label} · {formatDate(item.created_at)}
          </span>
        </div>
        <div className="mt-2 flex items-center gap-1 text-[10.5px] font-semibold text-[#8A2BE2]
                        bg-[#F3E8FF] border border-[#EDE5F8] rounded-[6px] px-2 py-1 w-fit">
          <svg width="10" height="10" viewBox="0 0 12 12" fill="none" stroke="currentColor" strokeWidth="1.6" strokeLinecap="round">
            <path d="M7.5 1H11v3.5M4.5 11H1V7.5M11 1L7 5M1 11l4-4"/>
          </svg>
          Click to expand
        </div>
      </div>
    </div>
  )
}

// ─── Content Row ──────────────────────────────────────────────────────────────
function ContentRow({
  item, isSelected, onToggle, onPreview,
}: {
  item: ContentResponse
  isSelected: boolean
  onToggle: () => void
  onPreview: (i: ContentResponse) => void
}) {
  const { mutate: togglePublish, isPending: togglingPub } = useTogglePublish()
  const { mutate: deleteItem,    isPending: deleting      } = useDeleteContentItem()

  return (
    <div
      className="group relative flex items-center gap-0 border-b transition-colors"
      style={{ borderColor: B.soft, background: isSelected ? B.wash : B.white }}
      onMouseEnter={e => { if (!isSelected) e.currentTarget.style.background = B.wash }}
      onMouseLeave={e => { if (!isSelected) e.currentTarget.style.background = B.white }}
    >
      {/* Checkbox col */}
      <div className="w-12 flex items-center justify-center shrink-0 py-4">
        <input type="checkbox" checked={isSelected} onChange={onToggle}
          className="w-[14px] h-[14px] rounded cursor-pointer" style={{ accentColor: B.purple }} />
      </div>

      {/* Type chip col */}
      <div className="w-12 flex items-center justify-center shrink-0">
        <TypeChip type={item.content_type} />
      </div>

      {/* Title / meta col */}
      <button onClick={() => onPreview(item)}
        className="flex-1 min-w-0 text-left py-4 pr-4">
        <p className="text-[13px] font-semibold truncate leading-snug transition-colors"
          style={{ color: B.ink }}
          onMouseEnter={e => (e.currentTarget.style.color = B.purple)}
          onMouseLeave={e => (e.currentTarget.style.color = B.ink)}
        >
          {item.title}
        </p>
        <p className="text-[11px] mt-0.5" style={{ color: B.faint }}>
          {formatDate(item.created_at)}
          {item.plan && (
            <span> · <span style={{ color: B.purple }}>{item.plan.name}</span></span>
          )}
        </p>
      </button>

      {/* Plan col */}
      <div className="w-[130px] shrink-0 hidden md:flex items-center">
        {item.plan
          ? <span className="text-[11.5px] font-semibold px-2.5 py-1 rounded-full border" style={{ color: B.purple, background: B.soft, borderColor: B.border }}>{item.plan.name}</span>
          : <span className="text-[11.5px]" style={{ color: B.faint }}>All subscribers</span>
        }
      </div>

      {/* Status col */}
      <div className="w-[108px] shrink-0 hidden sm:flex items-center">
        <StatusPill published={item.is_published} />
      </div>

      {/* Actions col */}
      <div className="w-[88px] shrink-0 flex items-center justify-end gap-1 pr-4">
        <button
          onClick={() => togglePublish(item.id)}
          disabled={togglingPub}
          title={item.is_published ? "Unpublish" : "Publish"}
          className="opacity-0 group-hover:opacity-100 w-7 h-7 rounded-[7px] flex items-center justify-center transition-all disabled:opacity-30"
          style={{ color: B.muted, border: `1px solid ${B.border}`, background: B.white }}
          onMouseEnter={e => { (e.currentTarget as HTMLElement).style.color = B.purple; (e.currentTarget as HTMLElement).style.background = B.soft }}
          onMouseLeave={e => { (e.currentTarget as HTMLElement).style.color = B.muted; (e.currentTarget as HTMLElement).style.background = B.white }}
        >
          {Icon.eye}
        </button>
        <button
          onClick={() => onPreview(item)}
          title="Preview"
          className="opacity-0 group-hover:opacity-100 w-7 h-7 rounded-[7px] flex items-center justify-center transition-all"
          style={{ color: B.muted, border: `1px solid ${B.border}`, background: B.white }}
          onMouseEnter={e => { (e.currentTarget as HTMLElement).style.color = B.purple; (e.currentTarget as HTMLElement).style.background = B.soft }}
          onMouseLeave={e => { (e.currentTarget as HTMLElement).style.color = B.muted; (e.currentTarget as HTMLElement).style.background = B.white }}
        >
          {Icon.file}
        </button>
        <button
          onClick={() => { if (confirm("Delete this content?")) deleteItem(item.id) }}
          disabled={deleting}
          title="Delete"
          className="opacity-0 group-hover:opacity-100 w-7 h-7 rounded-[7px] flex items-center justify-center transition-all disabled:opacity-30"
          style={{ color: B.faint, border: `1px solid ${B.border}`, background: B.white }}
          onMouseEnter={e => { (e.currentTarget as HTMLElement).style.color = "#EF4444"; (e.currentTarget as HTMLElement).style.background = "#FFF5F5"; (e.currentTarget as HTMLElement).style.borderColor = "#FECACA" }}
          onMouseLeave={e => { (e.currentTarget as HTMLElement).style.color = B.faint; (e.currentTarget as HTMLElement).style.background = B.white; (e.currentTarget as HTMLElement).style.borderColor = B.border }}
        >
          {Icon.trash}
        </button>
      </div>

      {/* Hover preview popover */}
      <ContentPreviewPopover item={item} />
    </div>
  )
}